const body = bh.input.body || {};

console.log("PreAuth Request Body:", body);

// Generate PreAuth ID
const today = new Date();

const yyyy = today.getFullYear();
const mm = String(today.getMonth() + 1).padStart(2, '0');
const dd = String(today.getDate()).padStart(2, '0');

const randomNo = Math.floor(10000 + Math.random() * 90000);

const preauthId = `PA-${yyyy}${mm}${dd}-${randomNo}`;


// Prepare DB payload
bh.local.preauthData = {

    preauth_id: preauthId,

    policy_no: body.policyNumber || "",

    patient_name: body.patientName || "",

    patient_age: body.patientAge || 0,

    hospital_name: body.hospitalName || "",

    diagnosis: body.diagnosis || "",

    procedure_code: body.procedureCode || "",

    room_category: body.roomCategory || "",

    length_of_stay: body.lengthOfStay || 0,

    requested_amount: body.requestedAmount || 0,

    estimated_payable: null,

    final_payable: null,

    mo_remarks: null,

    authorizer_remarks: null,

    status: "SUBMITTED",

    approval_number: null
};

console.log("Prepared PreAuth Data:", bh.local.preauthData);

const body = bh.input.body || {};

const preauthId = body.id;

console.log(
    "MO Action Request:",
    body
);

console.log(
    "PreAuth ID:",preauthId
);


// Validate action
if (
    !body.action
) {

    bh.local.response = {
        message: "Action is required"
    };

    return;
}


// Validate remark
if (
    !body.remark
) {

    bh.local.response = {
        message: "Remark is required"
    };

    return;
}


// Prepare update object
bh.local.moActionData = {

    preauth_id: preauthId,

    mo_remarks: body.remark
};


// APPROVE FLOW
if (
    body.action === "APPROVE"
) {

    bh.local.moActionData.status = "APPROVED";

    bh.local.response = {

        message: "MO Approved Successfully",

        preauth_id: preauthId,

        status: "APPROVED"
    };
}

//AUTHORIZER Flow
if (
    body.action === "AUTHORIZER"
) {

    bh.local.moActionData.status = "AUTHORIZER";

    bh.local.response = {

        message: "MO Approved Successfully",

        preauth_id: preauthId,

        status: "AUTHORIZER"
    };
}

// REJECT FLOW
if (
    body.action === "REJECT"
) {

    bh.local.moActionData.status =
        "REJECTED";

    bh.local.response = {

        message:
            "MO Rejected PreAuth",

        preauth_id: preauthId,

        status: "REJECTED"
    };
}


console.log(
    "Prepared MO Action Data:",
    bh.local.moActionData
);

console.log(
    "Updating PreAuth Request..."
);


// Execute update query payload
bh.local.updatePreAuthPayload = {

    preauth_id:
        bh.local.moActionData.preauth_id,

    mo_remarks:
        bh.local.moActionData.mo_remarks,

    status:
        bh.local.moActionData.status
};


console.log(
    "Update Payload:",
    bh.local.updatePreAuthPayload
);

const body = bh.input.body || {};

const preauthId = body.id;


// Validation
if (!body.action) {

    bh.local.response = {
        message: "Action is required"
    };

    return;
}


if (!body.remark) {

    bh.local.response = {
        message: "Remark is required"
    };

    return;
}


// Generate Approval Number
const today = new Date();

const yyyy =
    today.getFullYear();

const randomNo =
    Math.floor(
        10000 + Math.random() * 90000
    );

const approvalNumber =
    `APR-${yyyy}-${randomNo}`;



// Prepare Payload
bh.local.updatePayload = {

    preauth_id:
        preauthId,

    final_payable:
        body.final_payable || 0,

    authorizer_remarks:
        body.remark,

    updated_at:
        new Date()
};


// APPROVE FLOW
if (
    body.action === "APPROVE"
) {

    bh.local.updatePayload.status =
        "APPROVED";

    bh.local.updatePayload.approval_number =
        approvalNumber;

    bh.local.response = {

        message:
            "PreAuth Approved Successfully",

        preauth_id:
            preauthId,

        approval_number:
            approvalNumber,

        status:
            "APPROVED"
    };
}


// REJECT FLOW
if (
    body.action === "REJECT"
) {

    bh.local.updatePayload.status =
        "REJECTED";

    bh.local.updatePayload.approval_number =
        null;

    bh.local.response = {

        message:
            "PreAuth Rejected",

        preauth_id:
            preauthId,

        status:
            "REJECTED"
    };
}

const body = bh.input.body || {};

console.log("Routing Request:", body);

bh.local.payload = {

    ruleGroupId:
        "a7a6deef-b744-406a-a5ec-2f0bfda3bff5",

    version: "1.0.0",

    inputObj: {

        PatientAge:
            body.PatientAge,

        RequestedAmount:
            body.RequestedAmount
    }
};

console.log(
    "Prepared Payload:",
    bh.local.payload
);

const body = bh.input.body || {};

console.log("PreAuth Request Body:", body);

// Generate PreAuth ID
const today = new Date();

const yyyy = today.getFullYear();
const mm = String(today.getMonth() + 1).padStart(2, '0');
const dd = String(today.getDate()).padStart(2, '0');

const randomNo = Math.floor(10000 + Math.random() * 90000);

const preauthId = `PA-${yyyy}${mm}${dd}-${randomNo}`;


// Prepare DB payload
bh.local.preauthData = {

    preauth_id: preauthId,

    policy_no: body.policyNumber || "",

    patient_name: body.patientName || "",

    patient_age: body.patientAge || 0,

    hospital_name: body.hospitalName || "",

    diagnosis: body.diagnosis || "",

    procedure_code: body.procedureCode || "",

    room_category: body.roomCategory || "",

    length_of_stay: body.lengthOfStay || 0,

    requested_amount: body.requestedAmount || 0,

    estimated_payable: null,

    final_payable: null,

    mo_remarks: null,

    authorizer_remarks: null,

    status: "SUBMITTED",

    approval_number: null
};

console.log("Prepared PreAuth Data:", bh.local.preauthData);

const body = bh.input.body || {};

// console.log("Runtime Request:", body);


// Validate input object
if (!body.inputObj) {

    bh.local.response = {
        message: "inputObj is required"
    };

    return;
}


// Hardcoded payload
bh.local.payload = {

    workflowId:
        "df8503db-4d70-4754-b645-49939fe38c00",

    version: "1.0.0",

    inputObj: {

         preauth_id:
            body.inputObj.preauth_id,

        sumInsured:
            body.inputObj.sumInsured,

        RoomCategory:
            body.inputObj.RoomCategory,

        ProcedureCode:
            body.inputObj.ProcedureCode,

        requestedAmount:
            body.inputObj.requestedAmount,

        lengthOfStayDays:
            body.inputObj.lengthOfStayDays,

        PatientAge:body.inputObj.PatientAge
    }
};


// console.log(
//     "Prepared Payload:",
//     bh.local.payload
// );

// console.log(
//     "Runtime API Response:",
//     bh.local.result
// );

// Extract preauth id
const preauthId =
    bh.input.body.inputObj.preauth_id;

// Extract estimated payable
const estimatedPayable =
    bh.local.result.payload.result.estimatedPayable;

// Map Route → Status
const route =bh.local.result.payload.result.Route;
let status = "SUBMITTED";

if (route === "AUTO_APPROVE") {
    status = "APPROVED";
}
else if (route === "MO_REVIEW") {
    status = "MO_REVIEW";
}
else if (route === "MO_REVIEW+AUTHORIZER") {
    status = "";
}


// Prepare UPDATE payload
bh.local.updatePayload = {

    preauth_id: preauthId,

    estimated_payable: estimatedPayable,

    status: status
};


console.log(
    "Prepared Update Payload:",
    bh.local.updatePayload
);
